SELECT COUNT(DISTINCT PB.PK) AS QTD FROM LATTES_PRODBIB PB JOIN LATTES_P_PRODBIB PBP ON PBP.FK_PRODBIB = PB.PK JOIN SERVIDOR S ON S.PK_SIAPE = PBP.FK_SIAPE WHERE S.SIGLA_CAMPUS = 'ANA' AND (LOWER(S.AREA_INGRESSO) LIKE LOWER('%historia%') OR LOWER(S.AREA_INGRESSO) LIKE LOWER('%historia%')) AND (LOWER(PB.TIPO) = LOWER('capitulo de livro') OR LOWER(PB.TIPO) = LOWER('capitulo de livro')) AND PB.ANO = '2023'